{"content": "# -*- coding: utf-8 -*-
import socket

ports = []
for i in range(9000, 10000):
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(1)
    result = s.connect_ex(('127.0.0.1', i))
    if result == 0:
        ports.append(i)
    s.close()

print("Listening ports:", ports)

# Try to find Chrome CDP ports
for port in ports:
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(3)
    try:
        s.connect(('127.0.0.1', port))
        s.send(b'GET /json HTTP/1.1\r\nHost: localhost\r\n\r\n')
        resp = s.recv(4096)
        resp_str = resp.decode('utf-8', errors='replace')
        if 'websocketDebuggerUrl' in resp_str or 'webSocketDebuggerUrl' in resp_str or 'Title' in resp_str:
            print(f"  Port {port} -> CDP detected")
        elif 'HTTP' in resp_str:
            print(f"  Port {port} -> HTTP service ({resp_str[:100]})")
        else:
            print(f"  Port {port} -> Other service")
    except Exception as e:
        print(f"  Port {port} -> {e}")
    s.close()
